package ingest

import (
	"strings"

	"github.com/a<HOME>/agentic-rag-mcp/internal/domain"

	"gopkg.in/yaml.v3"
)

// ExtractFrontMatter parses YAML front matter from markdown content.
// Returns the parsed front matter and the remaining body content.
// If no front matter is present, returns zero FrontMatter and the full content.
func ExtractFrontMatter(content string) (domain.FrontMatter, string) {
	trimmed := strings.TrimSpace(content)
	if !strings.HasPrefix(trimmed, "---") {
		return domain.FrontMatter{}, content
	}

	// Find the closing ---
	rest := trimmed[3:]
	idx := strings.Index(rest, "\n---")
	if idx < 0 {
		return domain.FrontMatter{}, content
	}

	yamlBlock := rest[:idx]
	body := rest[idx+4:] // skip \n---
	// Trim leading newline from body
	body = strings.TrimPrefix(body, "\n")

	var fm domain.FrontMatter
	if err := yaml.Unmarshal([]byte(yamlBlock), &fm); err != nil {
		return domain.FrontMatter{}, content
	}

	// Parse raw map for arbitrary fields
	var raw map[string]any
	if err := yaml.Unmarshal([]byte(yamlBlock), &raw); err == nil {
		fm.Raw = raw
	}

	return fm, body
}
